import React, { useState, useEffect } from 'react';
import axiosInstance from '../api/axiosConfig';

const StudentDashboard = () => {
  const [courses, setCourses] = useState([]);
  const [enrolments, setEnrolments] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState({});
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    setLoading(true);
    setError('');
    try {
      // Fetch all courses
      const coursesRes = await axiosInstance.get('/api/courses');
      setCourses(coursesRes.data);

      // Fetch student's current enrolments
      const enrolmentsRes = await axiosInstance.get('/api/enrolments/my');
      setEnrolments(enrolmentsRes.data);
    } catch (err) {
      console.error(err);
      setError('Failed to load courses or enrolments. Please try again later.');
    } finally {
      setLoading(false);
    }
  };

  const handleEnrol = async (courseId) => {
    setError('');
    setSuccessMsg('');
    setActionLoading((prev) => ({ ...prev, [courseId]: true }));

    try {
      const response = await axiosInstance.post('/api/enrolments/enrol', { courseId });
      setSuccessMsg(`Successfully enrolled in "${response.data.courseTitle}"!`);
      // Update local enrolments state
      setEnrolments((prev) => [...prev, response.data]);
    } catch (err) {
      console.error(err);
      if (err.response && err.response.data && err.response.data.message) {
        setError(err.response.data.message);
      } else {
        setError('Enrolment failed. Please try again.');
      }
    } finally {
      setActionLoading((prev) => ({ ...prev, [courseId]: false }));
      // Clear success message after 4 seconds
      setTimeout(() => setSuccessMsg(''), 4000);
    }
  };

  // Helper to check if student is enrolled in a course
  const isEnrolled = (courseId) => {
    return enrolments.some((enrolment) => enrolment.courseId === courseId);
  };

  // Filter courses based on search query
  const filteredCourses = courses.filter((course) =>
    course.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    course.instructor.toLowerCase().includes(searchQuery.toLowerCase()) ||
    (course.description && course.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  return (
    <div className="container py-5 text-light">
      <div className="d-flex flex-column flex-md-row justify-content-between align-items-md-center gap-3 mb-5">
        <div>
          <h2 className="fw-bold bg-gradient-primary-to-secondary text-transparent bg-clip-text d-inline-block">
            Course Catalog
          </h2>
          <p className="text-muted mb-0">Browse through available courses and build your credentials</p>
        </div>
        <div style={{ maxWidth: '350px', width: '100%' }}>
          <div className="input-group">
            <span className="input-group-text bg-slate-800 border-secondary border-opacity-20 text-muted">
              🔍
            </span>
            <input
              type="text"
              className="form-control bg-slate-800 border-secondary border-opacity-20 text-light focus-primary"
              placeholder="Search title, instructor..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
        </div>
      </div>

      {successMsg && (
        <div className="alert alert-success border-0 bg-success bg-opacity-10 text-success rounded-3 mb-4 shadow-sm" role="alert">
          {successMsg}
        </div>
      )}

      {error && (
        <div className="alert alert-danger border-0 bg-danger bg-opacity-10 text-danger rounded-3 mb-4 shadow-sm" role="alert">
          {error}
        </div>
      )}

      {loading ? (
        <div className="d-flex flex-column align-items-center justify-content-center py-5">
          <div className="spinner-border text-primary mb-3" role="status">
            <span className="visually-hidden">Loading...</span>
          </div>
          <span className="text-muted">Loading courses...</span>
        </div>
      ) : filteredCourses.length === 0 ? (
        <div className="card bg-slate-800 border-0 text-center p-5 rounded-4 shadow-sm">
          <div className="card-body">
            <span className="fs-1 d-block mb-3">📚</span>
            <h4 className="fw-bold">No courses found</h4>
            <p className="text-muted mb-0">Try adjusting your search criteria or check back later.</p>
          </div>
        </div>
      ) : (
        <div className="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
          {filteredCourses.map((course) => {
            const enrolled = isEnrolled(course.id);
            return (
              <div className="col" key={course.id}>
                <div className="card h-100 border-0 bg-slate-800 text-light shadow-sm rounded-4 overflow-hidden card-hover transition">
                  <div className="card-body p-4 d-flex flex-column">
                    <div className="d-flex justify-content-between align-items-start mb-3">
                      <span className="badge bg-primary bg-opacity-10 text-primary px-3 py-2 rounded-pill fw-semibold">
                        {course.duration}
                      </span>
                      {enrolled && (
                        <span className="badge bg-success bg-opacity-10 text-success px-3 py-2 rounded-pill fw-semibold">
                          ✓ Enrolled
                        </span>
                      )}
                    </div>

                    <h5 className="card-title fw-bold text-white mb-2">{course.title}</h5>
                    <p className="card-text text-muted small flex-grow-1">
                      {course.description || 'No description provided for this course.'}
                    </p>

                    <hr className="border-secondary border-opacity-10 my-3" />

                    <div className="d-flex align-items-center gap-2 mb-4">
                      <div className="bg-slate-900 rounded-circle d-flex align-items-center justify-content-center" style={{ width: '36px', height: '36px' }}>
                        👨‍🏫
                      </div>
                      <div className="d-flex flex-column">
                        <span className="text-muted small">Instructor</span>
                        <span className="text-light fw-medium small">{course.instructor}</span>
                      </div>
                    </div>

                    <button
                      className={`btn w-100 py-2 rounded-3 fw-semibold ${
                        enrolled
                          ? 'btn-outline-success disabled bg-success bg-opacity-5'
                          : 'btn-primary shadow-sm'
                      }`}
                      onClick={() => handleEnrol(course.id)}
                      disabled={enrolled || actionLoading[course.id]}
                    >
                      {actionLoading[course.id] ? (
                        <>
                          <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                          Enrolling...
                        </>
                      ) : enrolled ? (
                        'Already Enrolled'
                      ) : (
                        'Enrol Now'
                      )}
                    </button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default StudentDashboard;
